import { Router } from "express";
import { ValidationError } from "../errors.js";
import {
  getProducts,
  getProductById,
  adjustProductStock,
} from "../services/product-service.js";

const router = Router();

// GET /products - list all products, optionally filter by category
router.get("/products", (req, res) => {
  const { category, minPrice, maxPrice } = req.query;

  const filters = {
    category: typeof category === "string" ? category : undefined,
    minPrice:
      typeof minPrice === "string" && !isNaN(parseFloat(minPrice))
        ? parseFloat(minPrice)
        : undefined,
    maxPrice:
      typeof maxPrice === "string" && !isNaN(parseFloat(maxPrice))
        ? parseFloat(maxPrice)
        : undefined,
  };

  res.json(getProducts(filters));
});

// GET /products/:id
router.get("/products/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const product = getProductById(id);

  if (!product) {
    res.status(404).json({ error: "Product not found" });
    return;
  }

  res.json(product);
});

// PATCH /products/:id/stock - update stock
router.patch("/products/:id/stock", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const { adjustment } = req.body as { adjustment: number };

  if (typeof adjustment !== "number") {
    res.status(400).json({ error: "adjustment must be a number" });
    return;
  }

  try {
    const product = adjustProductStock(id, adjustment);
    if (!product) {
      res.status(404).json({ error: "Product not found" });
      return;
    }
    res.json(product);
  } catch (e) {
    if (e instanceof ValidationError) {
      res.status(400).json({ error: e.message });
      return;
    }
    throw e;
  }
});

export { router as productRouter };

